INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$1203176F$$, 2026, $$The Combat Survivor Evader Locator (CSEL) System provides aircrews with end-to-end global satellite secure emergency communication capability during combat and
peace-time flying operations. CSEL provides a hand held radio as part of the mandatory aircrew survival gear. CSEL is a joint program (Air Force, Army, Navy, and US
Marine Corps) and is the DoD program of record for personnel recovery survival radios. CSEL supports four of five Personnel Mission Phases: Report, Locate, Support,
and Recover.

 A National Security Agency (NSA) Cryptographic Modernization mandate and the Ultra High Frequency Follow-On satellite constellation are at the end of life and are
 driving upgrades to base stations. This effort includes development to modernize the system to integrate common waveforms, integrate broadcast reception for non-
 CSEL devices. A portable interrogator will precisely locate the IP using the CSEL architecture without extensive audio communications that could compromise both
 rescue forces and IP. The portable interrogator will enable communication between IP and any designated aircraft not equipped with a AN/ARS-6 PLS Lightweight
 Airborne Radio System (LARS) or similar device as a Rescue Support Force (F-35, F-16, F-15E, Ground Teams etc.) asset.

 This program element may include necessary civilian pay expenses required to manage, execute, and deliver CSEL capabilities. The use of such program funds would
 be in addition to the civilian pay expenses budgeted in program elements 0605826F, 0605827F, 0605828F, 0605829F, 0605830F, 0605831F, 0605832F, 0605898F,
 and 0605833F. In FY 2024, $0.000M was expended for civilian pay expenses in this program element and in FY 2025 $0.000M is forecasted for civilian pay expenses in
 this program element.

 This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and
